Implement a per-sensor bounded in-memory queue with a reordering buffer to handle backpressure. Deduplicate incoming data using the composite key (sensorId, sequenceNumber) and reorder by timestamp before persistence. Store compact payloads locally using SQLite with Write-Ahead Logging (WAL) mode for optimal performance and crash recovery. The UI layer should bind to **throttled** Combine publishers (not debounced) that limit updates to approximately 30fps while preserving the most recent values for each sensor.

```swift
import SwiftUI
import Combine
import Foundation

// MARK: - Data Models
struct SensorReading: Codable, Identifiable {
    var id: String { "\(sensorId)-\(sequenceNumber)" }
    let sensorId: String
    let timestamp: Int64
    let sequenceNumber: Int32
    let value: Double
    let sensorType: SensorType

    enum SensorType: String, Codable {
        case pm25, co2, humidity
    }
}

struct SensorUpdate: Codable, Identifiable {
    var id: String { sensorId }
    let sensorId: String
    var latestReading: SensorReading?
    var lastUpdated: Date
}

// MARK: - Bounded Queue with Reordering
actor SensorDataPipeline {
    private let maxBufferSize = 1000
    private var pendingReads: [String: [SensorReading]] = [:]
    private var reorderingBuffer: [SensorReading] = []
    private var lastProcessedSeq: [String: Int32] = [:]

    private let deduplicationKey = Set<String>()

    func enqueue(_ reading: SensorReading) async -> Bool {
        let key = "\(reading.sensorId)-\(reading.sequenceNumber)"
        guard !deduplicationKey.contains(key) else { return false }

        if pendingReads[reading.sensorId] == nil {
            pendingReads[reading.sensorId] = []
        }

        if pendingReads[reading.sensorId]!.count >= maxBufferSize {
            return false // backpressure: buffer full
        }

        pendingReads[reading.sensorId]!.append(reading)
        return true
    }

    func processOrdered() -> [SensorReading] {
        reorderingBuffer.append(contentsOf: pendingReads.values.flatMap { $0 })
        pendingReads.removeAll()

        reorderingBuffer.sort { $0.timestamp < $1.timestamp }
        var result: [SensorReading] = []

        for reading in reorderingBuffer {
            let lastSeq = lastProcessedSeq[reading.sensorId] ?? -1
            if reading.sequenceNumber > lastSeq {
                result.append(reading)
                lastProcessedSeq[reading.sensorId] = reading.sequenceNumber
            }
        }
        reorderingBuffer.removeAll()
        return result
    }
}

// MARK: - SQLite Storage with WAL
class SensorDatabase: ObservableObject {
    @Published private(set) var latestReadings: [String: SensorReading] = [:]

    private var db: OpaquePointer?

    init() {
        sqlite3_open_v2("sensors.sqlite", &db, .readWriteCreate, nil)
        sqlite3_exec(db, "PRAGMA journal_mode=WAL", nil, nil, nil)
        sqlite3_exec(db, """
            CREATE TABLE IF NOT EXISTS readings (
                id TEXT PRIMARY KEY,
                sensorId TEXT, timestamp INTEGER,
                sequenceNumber INTEGER, value REAL, sensorType TEXT
            )
        """, nil, nil, nil)
    }

    func persist(_ readings: [SensorReading]) {
        for reading in readings {
            sqlite3_exec(db, """
                INSERT OR REPLACE INTO readings 
                (id, sensorId, timestamp, sequenceNumber, value, sensorType)
                VALUES (?, ?, ?, ?, ?, ?)
            """, reading)
        }
    }
}

// MARK: - Combine Pipeline
class SensorDataStore: ObservableObject {
    @Published var sensors: [String: SensorUpdate] = [:]

    private let pipeline = SensorDataPipeline()
    private let database = SensorDatabase()
    private var cancellables = Set<AnyCancellable>()

    private let bleSubject = PassthroughSubject<SensorReading, Never>()

    init() {
        bleSubject
            .collect(.byTime(DispatchQueue.global(), .milliseconds(33)))
            .map { readings in
                readings.sorted { $0.timestamp < $1.timestamp }
            }
            .sink { [weak self] ordered in
                Task { await self?.processBatch(ordered) }
            }
            .store(in: &cancellables)
    }

    private func processBatch(_ readings: [SensorReading]) async {
        for reading in readings {
            let accepted = await pipeline.enqueue(reading)
            guard accepted else { continue }

            await MainActor.run {
                sensors[reading.sensorId]?.latestReading = reading
                sensors[reading.sensorId]?.lastUpdated = Date()
            }
        }

        let processed = await pipeline.processOrdered()
        database.persist(processed)
    }

    func ingest(_ reading: SensorReading) {
        bleSubject.send(reading)
    }
}

// MARK: - SwiftUI View with Throttled Updates
struct DashboardView: View {
    @StateObject private var store = SensorDataStore()

    var body: some View {
        ScrollView {
            LazyVGrid(columns: [GridItem(.adaptive(minimum: 150))], spacing: 16) {
                ForEach(Array(store.sensors.values)) { sensor in
                    SensorCard(sensor: sensor)
                }
            }
            .padding()
        }
    }
}

struct SensorCard: View {
    let sensor: SensorUpdate

    var body: some View {
        VStack(alignment: .leading) {
            Text(sensor.sensorId)
                .font(.headline)
            if let reading = sensor.latestReading {
                Text(String(format: "%.1f", reading.value))
                    .font(.largeTitle)
                Text(reading.sensorType.rawValue)
                    .foregroundColor(.secondary)
            }
        }
        .padding()
        .background(RoundedRectangle(cornerRadius: 8).fill(Color.gray.opacity(0.1)))
    }
}

// MARK: - Test Plan
// Unit Tests:
// 1. Deduplication: Inject duplicate (sensorId, seqNum) → only one persisted
// 2. Backpressure: Enqueue >1000 readings → excess rejected
// 3. Reordering: Inject out-of-order timestamps → sorted output
// 4. Throttling: Emit 100 readings in 1s → ~30 renders
// 5. WAL Recovery: Crash during write → data recoverable
```

