```swift
import Foundation
import SQLite4

// MARK: - Data Models
struct Tile: Codable, Identifiable {
    let id: String
    let x: Int, y: Int, z: Int
    let data: Data
    let expiresAt: Date?
}

struct Route: Codable, Identifiable {
    let id: String
    var waypoints: [Waypoint]
    let version: UInt64
}

struct Waypoint: Codable {
    let id: String
    let lat: Double, lng: Double
    let address: String?
}

struct ETA: Codable {
    let routeId: String
    let driverId: String
    let secondsRemaining: Int
    let updatedAt: Date
}

// MARK: - CRDT Operations
enum Op: Codable {
    case addWaypoint(RouteId, Waypoint, LogicalClock)
    case removeWaypoint(RouteId, WaypointId, LogicalClock)
    case moveWaypoint(RouteId, WaypointId, Coordinate, LogicalClock)

    var lamportClock: UInt64
}

struct OpLog: Codable {
    var ops: [Op] = []
    var clock: UInt64 = 0
    var persistedOffset: Int = 0
}

// MARK: - SQLite Cache
final class TileCache {
    private let db: Connection

    func store(_ tile: Tile) throws {
        let tiles = Table("tiles")
        try db.run(tiles.insert(or: .replace,
            Column("id") <- tile.id,
            Column("x") <- tile.x, Column("y") <- tile.y, Column("z") <- tile.z,
            Column("data") <- tile.data,
            Column("expires_at") <- tile.expiresAt
        ))
    }

    func evictIfNeeded(maxMB: Int = 200) throws {
        // LRU eviction based on access time
    }
}

// MARK: - WebSocket + HTTP Fallback
protocol Transport {
    func sendETA(_ eta: ETA) async throws
    func streamRouteUpdates() -> AsyncStream<Route>
}

final class AdaptiveTransport: Transport {
    private var ws: URLSessionWebSocketTask?
    private let httpFallback: URLSession

    func sendETA(_ eta: ETA) async throws {
        if let ws = ws, ws.state == .running {
            try await ws.send(ETA.encode(eta))
        } else {
            try await httpFallback.post("/api/eta", body: eta)
        }
    }
}

// MARK: - Crash-Safe Resume
final class RouteManager {
    private let opLog: OpLog
    private let cache: TileCache
    private let transport: Transport

    func applyOp(_ op: Op) throws {
        opLog.ops.append(op)
        opLog.clock = max(opLog.clock, op.lamportClock) + 1
        try persistOpLog() // WAL to survive crashes
        try replayOpsToState(op: op)
    }

    private func persistOpLog() throws {
        let data = try JSONEncoder().encode(opLog)
        try data.write(to: .opLogURL, options: .atomic)
    }
}

// MARK: - SwiftUI View
struct ETABadge: View {
    let eta: ETA
    var body: some View {
        HStack(spacing: 4) {
            Image(systemName: "car.fill")
            Text("\(eta.secondsRemaining / 60) min")
                .font(.headline)
        }
        .padding(.horizontal, 12).padding(.vertical, 6)
        .background(Color.blue, in: Capsule())
    }
}

struct DriverAvatarStack: View {
    let drivers: [Driver]
    var body: some View {
        HStack(spacing: -8) {
            ForEach(drivers.prefix(3)) { driver in
                AsyncImage(driver.avatarURL) { img in
                    img.resizable().scaledToFill()
                }
                .frame(width: 32, height: 32)
                .clipShape(Circle())
                .overlay(Circle().stroke(Color.white, lineWidth: 2))
            }
            if drivers.count > 3 {
                Text("+\(drivers.count - 3)")
                    .font(.caption).foregroundStyle(.white)
                    .frame(width: 32, height: 32)
                    .background(Color.gray, in: Circle())
            }
        }
    }
}
```

questions.explanation:
## Why This Is Asked
This question tests hands-on iOS fundamentals: camera usage with AVFoundation, barcode and QR code scanning, simple data modeling with Codable, and local file persistence. It also evaluates the candidate's ability to design a smooth UX flow that transitions naturally between scanning and reviewing results.

## Key Concepts
- **AVFoundation capture session and metadata output** — Configure an `AVCaptureSession` with an `AVCaptureMetadataOutput` to detect barcode and QR code symbologies.
- **Codable persistence in the Documents directory** — Encode and decode a `[Product]` array to a JSON file for lightweight local storage.
- **SwiftUI state management and List filtering** — Use `@State` or `@ObservableObject` to drive a searchable, filterable list of scanned products.
- **Camera UX** — Handle camera permissions gracefully, resume the capture session after each scan, and provide clear user feedback.

## Code Example
```swift
import SwiftUI
import AVFoundation

// MARK: - Model

struct Product: Codable, Identifiable {
    let id: String
    let name: String
    let price: Double
    var tags: [String] = []
}

// MARK: - Mock Backend

let mockProducts: [String: Product] = [
    "123456": Product(id: "123456", name: "Wireless Mouse", price: 29.99, tags: ["electronics"]),
    "789012": Product(id: "789012", name: "USB-C Cable", price: 9.99, tags: ["accessories"])
]

// MARK: - Persistence

func productsFileURL() -> URL {
    FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
        .appendingPathComponent("scanned_products.json")
}

func saveProducts(_ products: [Product]) {
    if let data = try? JSONEncoder().encode(products) {
        try? data.write(to: productsFileURL())
    }
}

func loadProducts() -> [Product] {
    guard let data = try? Data(contentsOf: productsFileURL()) else { return [] }
    return (try? JSONDecoder().decode([Product].self, from: data)) ?? []
}

// MARK: - Scanner Coordinator (AVFoundation bridge)

class ScannerCoordinator: NSObject, AVCaptureMetadataOutputObjectsDelegate {
    var onCodeScanned: ((String) -> Void)?

    func metadataOutput(_ output: AVCaptureMetadataOutput,
                        didOutput metadataObjects: [AVMetadataObject],
                        from connection: AVCaptureConnection) {
        if let object = metadataObjects.first as? AVMetadataMachineReadableCodeObject,
           let value = object.stringValue {
            onCodeScanned?(value)
        }
    }
}

// MARK: - SwiftUI Views (minimal sketch)

struct ContentView: View {
    @State private var scannedProducts: [Product] = loadProducts()
    @State private var searchText = ""
    @State private var selectedTag: String?
    @State private var isScanning = true

    var filteredProducts: [Product] {
        scannedProducts.filter { product in
            (searchText.isEmpty || product.name.localizedCaseInsensitiveContains(searchText)) &&
            (selectedTag == nil || product.tags.contains(selectedTag!))
        }
    }

    var body: some View {
        NavigationStack {
            if isScanning {
                // Placeholder for the camera preview wrapped via UIViewRepresentable
                Text("Camera Preview")
                    .frame(maxWidth: .infinity, maxHeight: .infinity)
                    .background(Color.black)
            } else {
                List(filteredProducts) { product in
                    HStack {
                        Text(product.name)
                        Spacer()
                        Text(String(format: "$%.2f", product.price))
                    }
                }
                .searchable(text: $searchText, prompt: "Search by name")
            }
        }
    }

    func handleScan(_ code: String) {
        guard let product = mockProducts[code] else { return }
        scannedProducts.append(product)
        saveProducts(scannedProducts)
        // Briefly show the result, then resume scanning
        isScanning = false
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) {
            isScanning = true
        }
    }
}
```

## Follow-Up Questions
- How would you handle camera permission denials and guide the user to Settings?
- What changes are needed to replace the mock dictionary with a real network call?
- How could you migrate from file-based JSON persistence to Core Data or SwiftData as the app grows?
- What strategies would you use to prevent duplicate scans in rapid succession?

