questions.answer:
Implement a Transaction model with id, title, amount, and date properties conforming to both Codable and Identifiable. Create a NetworkService using URLSession to fetch an array of transactions, decode them with JSONDecoder, and expose the data via a @Published property in an ObservableObject. For persistence, use FileManager to save the encoded data to the documents directory, loading from disk on app launch and caching fresh data after each successful network fetch. Wrap the network call in a Result type to handle errors gracefully, and display a retry button when the request fails. The SwiftUI view should observe the NetworkService and render a List of transactions, conditionally showing an error state with a retry button when data loading fails.

```swift
struct Transaction: Identifiable, Codable {
    let id: UUID
    let title: String
    let amount: Double
    let date: Date
}

class TransactionService: ObservableObject {
    @Published var transactions: [Transaction] = []
    @Published var error: Error?
    @Published var isLoading: Bool = false

    private let fileURL: URL

    init() {
        let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
        fileURL = documentsPath.appendingPathComponent("transactions.json")
        loadFromDisk()
    }

    func fetch() {
        isLoading = true
        error = nil

        URLSession.shared.dataTask(with: URL(string: "https://api.example.com/transactions")!) { [weak self] data, response, error in
            DispatchQueue.main.async {
                self?.isLoading = false
                if let error = error {
                    self?.error = error
                    return
                }
                guard let data = data else { return }
                do {
                    self?.transactions = try JSONDecoder().decode([Transaction].self, from: data)
                    self?.saveToDisk()
                } catch {
                    self?.error = error
                }
            }
        }.resume()
    }

    private func saveToDisk() {
        try? JSONEncoder().encode(transactions).write(to: fileURL)
    }

    private func loadFromDisk() {
        guard let data = try? Data(contentsOf: fileURL),
              let saved = try? JSONDecoder().decode([Transaction].self, from: data) else { return }
        transactions = saved
    }
}

struct TransactionListView: View {
    @StateObject private var service = TransactionService()

    var body: some View {
        Group {
            if service.isLoading {
                ProgressView()
            } else if let error = service.error {
                VStack {
                    Text("Failed to load: \(error.localizedDescription)")
                    Button("Retry") { service.fetch() }
                }
            } else {
                List(service.transactions) { transaction in
                    VStack(alignment: .leading) {
                        Text(transaction.title)
                        Text(String(format: "$%.2f", transaction.amount))
                            .foregroundColor(transaction.amount < 0 ? .red : .green)
                    }
                }
            }
        }
        .onAppear { service.fetch() }
    }
}
```

## Basic Test Plan

1. **Unit Tests**: Test Transaction model encoding/decoding, verify JSON parsing handles valid and invalid data
2. **Integration Tests**: Mock network responses to test service behavior, verify disk caching works correctly
3. **UI Tests**: Verify List displays transactions, error state shows retry button, tapping retry triggers fetch

questions.explanation:
## Why This Is Asked
This question tests practical local persistence, SwiftUI queries, and basic user experience actions without requiring remote data.

## Key Concepts
- Codable persistence to the local Documents directory
- File-based store with load/save and proper error handling
- SwiftUI List with searchable and dynamic filtering by multiple fields
- Row actions: copy to clipboard and share sheet
- Basic test plan and empty-state handling

## Code Example
```swift
struct Snippet: Codable, Identifiable {
    let id: UUID
    var title: String
    var content: String
    var tag: String
    var createdDate: Date
}

class SnippetStore: ObservableObject {
    @Published var snippets: [Snippet] = []

    private let fileName = "snippets.json"

    private var fileURL: URL {
        FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
            .appendingPathComponent(fileName)
    }

    func load() {
        guard FileManager.default.fileExists(atPath: fileURL.path) else { return }
        do {
            let data = try Data(contentsOf: fileURL)
            snippets = try JSONDecoder().decode([Snippet].self, from: data)
        } catch {
            print("Failed to load: \(error)")
        }
    }

    func save() {
        do {
            let data = try JSONEncoder().encode(snippets)
            try data.write(to: fileURL)
        } catch {
            print("Failed to save: \(error)")
        }
    }
}

struct ContentView: View {
    @StateObject private var store = SnippetStore()
    @State private var searchText = ""

    var filteredSnippets: [Snippet] {
        if searchText.isEmpty { return store.snippets }
        let query = searchText.lowercased()
        return store.snippets.filter {
            $0.title.lowercased().contains(query) ||
            $0.content.lowercased().contains(query) ||
            $0.tag.lowercased().contains(query)
        }
    }

    var body: some View {
        NavigationStack {
            Group {
                if store.snippets.isEmpty {
                    ContentUnavailableView(
                        "No Snippets",
                        systemImage: "doc.text",
                        description: Text("Add your first snippet to get started")
                    )
                } else {
                    List(filteredSnippets) { snippet in
                        VStack(alignment: .leading) {
                            Text(snippet.title).font(.headline)
                            Text(snippet.content).lineLimit(2).foregroundStyle(.secondary)
                            Text(snippet.tag).font(.caption).padding(4).background(Color.blue.opacity(0.2)).cornerRadius(4)
                        }
                        .contextMenu {
                            Button("Copy") {
                                UIPasteboard.general.string = snippet.content
                            }
                            ShareLink(item: snippet.content)
                        }
                    }
                }
            }
            .navigationTitle("SnippetBook")
            .searchable(text: $searchText, prompt: "Search snippets")
            .onAppear { store.load() }
        }
    }
}
```

## Test Plan
1. **Persistence Test**: Launch app, add snippets, kill app, relaunch — snippets should persist
2. **Search Test**: Type in search field — results should filter by title, content, or tag
3. **Empty State Test**: Launch fresh — empty state should display
