## OR-Set Implementation Sketch
```swift
struct ORSet<T: Hashable> {
    private var adds: [T: VectorClock] = [:]
    private var removes: [T: VectorClock] = [:]

    mutating func add(_ element: T, clock: VectorClock) {
        adds[element] = clock
    }

    mutating func remove(_ element: T, clock: VectorClock) {
        removes[element] = clock
    }

    func lookup(_ element: T) -> Bool {
        guard let addClock = adds[element] else { return false }
        guard let removeClock = removes[element] else { return true }
        return addClock > removeClock
    }

    func merge(with other: ORSet<T>) -> ORSet<T> {
        var result = self
        for (elem, clock) in other.adds {
            result.adds[elem] = max(result.adds[elem] ?? [:], clock)
        }
        for (elem, clock) in other.removes {
            result.removes[elem] = max(result.removes[elem] ?? [:], clock)
        }
        return result
    }
}
```

