func metric(_ expr: String) -> Metric {
    let tokens = expr.split(separator: " ")
    // Parse: SUM(events) WHERE tenant='t1'
    guard tokens.count >= 4, tokens[0] == "SUM",
          tokens[2] == "WHERE", tokens[3].starts(with: "tenant=") else {
        throw DSLError.invalidExpression
    }
    return Metric(aggregation: .sum, field: String(tokens[1]), 
                 filter: parseFilter(tokens[3...]))
}

// Secure Enclave key management
struct TenantKeyManager {
    func generateKey(for tenantId: String) throws -> SecKey {
        var error: Unmanaged<CFError>?
        let access = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly,
            .privateKeyUsage, &error
        )!
        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecAttrTokenID as String: kSecAttrTokenIDSecureEnclave,
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: tenantId.data(using: .utf8)!,
                kSecAttrAccessControl as String: access
            ]
        ]
        return SecKeyCreateRandomKey(attributes as CFDictionary, &error)!
    }
}

