```swift
class MoodStore: ObservableObject {
    @Published var entries: [MoodEntry] = []

    private let url: URL
    private let fileManager = FileManager.default
    private let queue = DispatchQueue(label: "com.moodgraph.persistence")

    init() {
        let documentsURL = fileManager.urls(for: .documentDirectory, in: .userDomainMask)[0]
        self.url = documentsURL.appendingPathComponent("mood_entries.json")
        load()
    }

    func addEntry(mood: Int, note: String?) {
        let entry = MoodEntry(id: UUID(), date: Date(), mood: mood, note: note)
        entries.append(entry)
        save()
    }

    private func save() {
        queue.async { [weak self] in
            guard let self = self else { return }
            do {
                let data = try JSONEncoder().encode(self.entries)
                let tempURL = self.url.deletingLastPathComponent()
                    .appendingPathComponent("mood_entries_temp.json")
                try data.write(to: tempURL, options: .atomic)
                try fileManager.moveItem(at: tempURL, to: self.url)
            } catch {
                print("Failed to save: \(error)")
            }
        }
    }

    private func load() {
        guard fileManager.fileExists(atPath: url.path) else { return }
        do {
            let data = try Data(contentsOf: url)
            entries = try JSONDecoder().decode([MoodEntry].self, from: data)
        } catch {
            print("Failed to load: \(error)")
        }
    }

    func dailyAverages() -> [(date: Date, average: Double)] {
        let calendar = Calendar.current
        let grouped = Dictionary(grouping: entries) { entry in
            calendar.startOfDay(for: entry.date)
        }
        return grouped.map { (date, entries) in
            let avg = Double(entries.reduce(0) { $0 + $1.mood }) / Double(entries.count)
            return (date: date, average: avg)
        }.sorted { $0.date < $1.date }
    }
}
