// CRDT fragment merge (high level)
struct Fragment: Identifiable {
    let id: UUID
    var content: String
    var tombstoned: Bool
}

// Merge rule: tombstoned copies take precedence
func merge(fragments: [Fragment]) -> [Fragment] {
    return fragments.reduce(into: [:]) { merged, fragment in
        if fragment.tombstoned {
            merged[fragment.id] = fragment
        } else if merged[fragment.id] == nil {
            merged[fragment.id] = fragment
        }
    }.values.sorted { $0.id < $1.id }
}
```

